# First, find sensors with 'potentiostat' in their label
sparql1 = """
PREFIX sosa: <http://www.w3.org/ns/sosa/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?sensor ?label WHERE {
  GRAPH <http://localhost:8080/graph/entities> {
    ?sensor a sosa:Sensor ;
            rdfs:label ?label .
    FILTER(CONTAINS(LCASE(?label), 'potentiostat'))
  }
}
"""
result1 = sparql_query(sparql1)
print(result1)

# Get all observations made by the potentiostat sensor
# Try Pattern A first (simple scalar)
sparql_obs = """
PREFIX sosa: <http://www.w3.org/ns/sosa/>
SELECT ?obs ?result ?time WHERE {
  GRAPH <http://localhost:8080/graph/observations> {
    ?obs a sosa:Observation ;
         sosa:madeBySensor <http://localhost:8080/entity/sensor-eis-beta> ;
         sosa:hasSimpleResult ?result ;
         sosa:resultTime ?time .
  }
}
ORDER BY DESC(?time)
"""
result_a = sparql_query(sparql_obs)
print("Pattern A:", result_a)

# Try Pattern B (SIO measurement chain) to check for additional observations
sparql_obs_b = """
PREFIX sosa: <http://www.w3.org/ns/sosa/>
PREFIX sio: <http://semanticscience.org/resource/>
SELECT ?obs ?value ?time WHERE {
  GRAPH <http://localhost:8080/graph/observations> {
    ?obs a sosa:Observation ;
         sosa:madeBySensor <http://localhost:8080/entity/sensor-eis-beta> ;
         sosa:resultTime ?time ;
         sio:has-attribute ?mv .
    ?mv a sio:MeasuredValue ;
        sio:has-value ?value .
  }
}
ORDER BY DESC(?time)
"""
result_b = sparql_query(sparql_obs_b)
print("Pattern B:", result_b)

# Compile the final answer
sensor_uri = "http://localhost:8080/entity/sensor-eis-beta"
sensor_label = "EIS potentiostat Beta"

import json
result_a_data = json.loads('{"head":{"vars":["obs","result","time"]},"results":{"bindings":[{"obs":{"type":"uri","value":"http://localhost:8080/entity/test-obs-p5-2b"},"result":{"type":"literal","value":"91.3","datatype":"http://www.w3.org/2001/XMLSchema#double"},"time":{"type":"literal","value":"2026-02-24T10:05:00Z","datatype":"http://www.w3.org/2001/XMLSchema#dateTime"}},{"obs":{"type":"uri","value":"http://localhost:8080/entity/test-obs-p5-2a"},"result":{"type":"literal","value":"88.1","datatype":"http://www.w3.org/2001/XMLSchema#double"},"time":{"type":"literal","value":"2026-02-24T10:00:00Z","datatype":"http://www.w3.org/2001/XMLSchema#dateTime"}}]}}')

observations = result_a_data["results"]["bindings"]
for obs in observations:
    print(f"Observation: {obs['obs']['value']}, Result: {obs['result']['value']}, Time: {obs['time']['value']}")

final_sparql = """PREFIX sosa: <http://www.w3.org/ns/sosa/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?obs ?sensor ?label ?result ?time WHERE {
  GRAPH <http://localhost:8080/graph/entities> {
    ?sensor a sosa:Sensor ;
            rdfs:label ?label .
    FILTER(CONTAINS(LCASE(?label), 'potentiostat'))
  }
  GRAPH <http://localhost:8080/graph/observations> {
    ?obs a sosa:Observation ;
         sosa:madeBySensor ?sensor ;
         sosa:hasSimpleResult ?result ;
         sosa:resultTime ?time .
  }
}
ORDER BY DESC(?time)"""

answer = (
    "Found 2 observations from sensors whose label contains 'potentiostat':\n\n"
    f"Sensor: {sensor_label} ({sensor_uri})\n\n"
    "1. Observation: http://localhost:8080/entity/test-obs-p5-2b\n"
    "   Result: 91.3\n"
    "   Time: 2026-02-24T10:05:00Z\n\n"
    "2. Observation: http://localhost:8080/entity/test-obs-p5-2a\n"
    "   Result: 88.1\n"
    "   Time: 2026-02-24T10:00:00Z"
)

sources = [
    "http://localhost:8080/entity/test-obs-p5-2b",
    "http://localhost:8080/entity/test-obs-p5-2a",
    "http://localhost:8080/entity/sensor-eis-beta"
]

print(answer)
print("\nSPARQL used:")
print(final_sparql)

SUBMIT(answer, final_sparql, sources)

